#include <bits/stdc++.h>
using namespace std;
struct Node{
    int u,v;
};
int n,a[200005],nxt[200005],pre[200005],sum=0;
bool t[200005],used[200005];
priority_queue<Node> p;
queue<Node> ans;
bool operator<(Node x,Node y){
	if(abs(a[x.u]-a[x.v])==abs(a[y.u]-a[y.v]))
		return x.u>y.u;
    return abs(a[x.u]-a[x.v])>abs(a[y.u]-a[y.v]);
}
int main(){
    string s;
    scanf("%d",&n);
    cin>>s;
    for(int i=1;i<=n;i++)
        t[i]=(s[i-1]=='G');
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<n;i++){
        if(t[i]^t[i+1])
            p.push({i,i+1});
        nxt[i]=i+1,pre[i+1]=i;
    }
    while(p.size()){
        int x=p.top().u,y=p.top().v;
        p.pop();
        if(used[x] || used[y])
            continue;
        used[x]=used[y]=1;
        sum++;
        ans.push({x,y});
        if(pre[x] && nxt[y] && t[pre[x]]^t[nxt[y]])
            p.push({pre[x],nxt[y]});
        if(pre[x])
            nxt[pre[x]]=nxt[y];
        if(nxt[y])
            pre[nxt[y]]=pre[x];
    }
    cout<<sum<<'\n';
    for(int i=1;i<=sum;i++){
    	cout<<ans.front().u<<' '<<ans.front().v<<'\n'; 
    	ans.pop();
	}
    return 0;
}
